#!/usr/bin/env bash
# workflow-3.sh — 被动指数工作流（定配置 → 最低费率宽基 → 自动定投 → 阈值再平衡 → 什么都不做） SOP walkthrough for 个人投资理财.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="个人投资理财"
WORKFLOW="被动指数工作流（定配置 → 最低费率宽基 → 自动定投 → 阈值再平衡 → 什么都不做）"

usage() {
  cat <<EOF
workflow-3.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-3.sh             # interactive
  ./workflow-3.sh --dry-run
  ./workflow-3.sh --json
  ./workflow-3.sh --explain
  ./workflow-3.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "被动指数工作流（定配置 → 最低费率宽基 → 自动定投 → 阈值再平衡 → 什么都不做）" 工作流。

一句话: 从「我不想也不该花时间选股/择时」到「一个买全市场低成本指数、自动定投、几乎不动手的组合」—— ≥80% 自主投资者的最优默认。本派是 Workflow 1 主工作流在「选品」一步走「宽基指数」的纯净版，把人为干预降到最低。SPIVA 是其弹药：YE2025 美国 79% 大盘主动跑输 S&P 500。(evidence: [T03-S001, T03-S021])

入门 SOP 共 5 步, 失败模式自检 5 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定配置（三基金 / 目标日期）**：定股债比 + 国际比例。两条路：① 自建三基金（美股全市场 + 国际股 + 债券）；② 偷懒到极致 = **一只目标日期基金**（自动含配置+再平衡+随龄滑翔降风险）。(evidence: [T03-S004, T03-S009, T03-S010])"
  "**选最低费率宽基**：在选定资产类别里挑费率最低、跟踪误差最小的宽基（VTI/VXUS/BND 或 VT；CN 沪深300/标普500 QDII 宽基指基）。被动派第一纪律 = 最小化费率。(evidence: [T03-S004])"
  "**自动定投**：在券商设定额定期自动申购（工资到账即扣），把「要不要现在买」的决策彻底自动化。(evidence: [T03-S005])"
  "**阈值 / 日历再平衡**：设触发规则（日历法：每年固定一天；或阈值法：5/25 规则）把权重拉回。详见 Workflow 6。(evidence: [T03-S006])"
  "**「什么都不做」（核心纪律）**：除再平衡/复盘外，**不**响应市场噪音、不择时、不追热点。这一步是被动工作流**最难且最增值**的部分。(evidence: [T03-S001, T03-S016])"
)
declare -a FAILURE_MODES=(
  "**熊市底部恐慌清仓**：被动工作流唯一的真失败点 —— 在最该继续买时卖出，锁死亏损。自检：你写了「跌 X% 我不卖/继续投」预案吗？"
  "**以为「被动」=「随便买个 ETF」**：买了高费率/主题/杠杆 ETF 当被动。自检：你买的是覆盖全市场的最低费率宽基吗？"
  "**手动择时取代自动定投**：「等跌了再买」踏空。自检：你设了自动定投把决策自动化了吗？"
  "**给被动组合叠加择时/选股工具**：上 TradingView/选股软件徒增复杂度与出错面（→ T02 反模式）。自检：你是不是在给一个本该「无聊」的组合加戏？"
  "**robo 双重收费不自知**：0.25% 顾问费叠加在基金 ER 之上，小账户不划算。自检：直接自持宽基 ETF 是不是更省？"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-3-walkthrough"
fi
